import json, sys
from pathlib import Path
DATA_PATH = Path("todos.json")
def load_items(path=DATA_PATH):
    if not path.exists(): return []
    return json.loads(path.read_text())
def save_items(items, path=DATA_PATH): path.write_text(json.dumps(items, indent=2))
def next_id(items): return 1 if not items else max(item["id"] for item in items) + 1
def add_item(text, path=DATA_PATH):
    items=load_items(path); item={"id":next_id(items),"text":text,"done":False,"completed_at":None}; items.append(item); save_items(items,path); return item
def list_items(path=DATA_PATH): return load_items(path)
def mark_done(item_id, timestamp, path=DATA_PATH):
    items=load_items(path)
    for item in items:
        if item["id"]==item_id:
            if not item["done"]: item["done"]=True; item["completed_at"]=timestamp
    save_items(items,path); return items
def delete_item(item_id, path=DATA_PATH):
    items=[item for item in load_items(path) if item["id"] != item_id]; save_items(items,path); return items
def main(argv):
    if len(argv)<2: raise SystemExit("usage")
    cmd=argv[1]
    if cmd=="add": add_item(" ".join(argv[2:]))
    elif cmd=="list": [print(item) for item in list_items()]
    elif cmd=="done": mark_done(int(argv[2]), argv[3])
    elif cmd=="delete": delete_item(int(argv[2]))
    else: raise SystemExit(f"unknown command: {cmd}")
if __name__=="__main__": main(sys.argv)

